window.debugOptimaSPA=function(){if(window.optimaSPA){const activeLink=document.querySelector('.nav-link.active');if(activeLink){}else{}const allLinks=document.querySelectorAll('.nav-link[href]')}};window.testSPANavigation=function(url='/dashboard'){if(window.optimaSPA){window.optimaSPA.navigateTo(url)}else{console.error('❌ SPA not initialized')}};window.refreshSPAPage=function(){if(window.optimaSPA){window.optimaSPA.refreshCurrentPage()}else{console.error('❌ SPA not initialized')}};window.checkSPAStatus=function(){const status={spaInitialized:!!window.optimaSPA,spaUnifiedLoaded:window.OPTIMA_SPA_UNIFIED_INITIALIZED,dataRefreshLoaded:!!window.OptimaDataRefresh,sidebar:!!document.getElementById('sidebar'),mainContent:!!document.querySelector('.content-body')};const allGood=Object.values(status).every(v=>v===true);return status};